        <TextInput
          data-cy="login-password"
          label="Password"
          onChange={(e) => setPassword(e.target.value)}
          type="password"
          value={password}
        />
        <StyledButton
          data-cy="login-submit"
          onClick={() => localLogin({ password, username })}
