const ProjectFiltersModal: React.FC<ProjectFiltersModalProps> = ({
  open,
  setOpen,
}) => {
  const { sendEvent } = useLogWindowAnalytics();
  const [filters, setFilters] = useFilterParam();
  const { logMetadata } = useLogContext();
  const { execution, taskID } = logMetadata ?? {};
  const { loading: taskQueryLoading, task } = useTaskQuery({
    execution,
    taskID,
  });
  const projectId = task?.versionMetadata?.projectMetadata?.id ?? "";
  const { data, loading: projectFiltersLoading } = useQuery<
    ProjectFiltersQuery,
    ProjectFiltersQueryVariables
  >(
    PROJECT_FILTERS,
    projectId
      ? {
          variables: { projectId },
        }
      : skipToken,
  );

  const parsleyFilters = useMemo(
    () => data?.project?.parsleyFilters ?? [],
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [projectFiltersLoading],
  );

  // A row is disabled if the filter it represents is already in the URL.
  const isRowDisabled = useCallback(
    (index: number) => {
      const parsleyFilter = parsleyFilters[index];
      if (!parsleyFilter) return false;
      const filterStr = stringifyFilter(
        convertParsleyFilterToFilter(parsleyFilter),
      );
      return filters.some((f) => stringifyFilter(f) === filterStr);
    },
    [filters, parsleyFilters],
  );

  const [rowSelection, setRowSelection] = useState<RowSelectionState>({});

  useEffect(() => {
    // Determine the initial selection of filters. If a filter is already in the URL, it should be checked.
    const initialSelection: RowSelectionState = parsleyFilters.reduce(
      (acc, _, index) => {
        if (isRowDisabled(index)) acc[index] = true;
        return acc;
      },
      {} as RowSelectionState,
    );
    setRowSelection(initialSelection);
  }, [isRowDisabled, parsleyFilters]);

  const table = useLeafyGreenTable({
    columns,
    data: parsleyFilters,
    enableColumnFilters: false,
    enableRowSelection: (row) => !isRowDisabled(row.index),
    enableSorting: false,
    hasSelectableRows: true,

    onRowSelectionChange: onChangeHandler(setRowSelection),
    state: { rowSelection },
  });

  const handleConfirm = useCallback(() => {
    const selectedFilters = table
      .getSelectedRowModel()
      .rows.map(({ original }) => original);
    const newFilters = selectedFilters.map(convertParsleyFilterToFilter);
    const deduplicated = deduplicateFilters(filters, newFilters);
    setFilters(deduplicated);

    leaveBreadcrumb(
      "applied-project-filters",
      { filters: selectedFilters },
      SentryBreadcrumbTypes.User,
    );

    sendEvent({
      "filter.expressions": selectedFilters.map((f) => f.expression),
      name: "Used project filters",
    });

    setOpen(false);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [filters, setFilters]);

  const hasNewFilters = table.getSelectedRowModel().rows.length > 0;

  return (
    <ConfirmationModal
      cancelButtonProps={{ onClick: () => setOpen(false) }}
      confirmButtonProps={{
        children: "Apply filters",
        disabled: !hasNewFilters,
        onClick: handleConfirm,
      }}
      data-cy="project-filters-modal"
      open={open}
      setOpen={setOpen}
      // @ts-expect-error - size is not a valid prop for ConfirmationModal but it is valid for the underlying Modal component
      size="large"
      title="Project Filters"
    >
      <BaseTable
        disabledRowIndexes={parsleyFilters
          .map((_, index) => index)
          .filter(isRowDisabled)}
        emptyComponent={
          <TablePlaceholder
            data-cy="no-filters-message"
            glyph="MagnifyingGlass"
            message={
              <p>
                No filters found! Project filters can be defined in the{" "}
                <Link
                  href={getProjectSettingsURL(projectId, "views-and-filters")}
                >
                  project settings
                </Link>
                .
              </p>
            }
          />
        }
        loading={projectFiltersLoading || taskQueryLoading}
        rowCss={css`
          border-bottom: 1px solid ${gray.light2};
        `}
        shouldAlternateRowColor
        table={table}
        verticalAlignment="top"
      />

export enum TaskStatus {
  Inactive = "inactive",

  // TaskUnstarted is assigned to a display task after cleaning up one of
  // its execution tasks. This indicates that the display task is
  // pending a rerun
  Unstarted = "unstarted",

  // TaskUndispatched indicates either
  //  1. a task is not scheduled to run (when Task.Activated == false)
  //  2. a task is scheduled to run (when Task.Activated == true)
  Undispatched = "undispatched",
  WillRun = "will-run",
  Unscheduled = "unscheduled",

  // TaskStarted indicates a task is currently running
  Started = "started",

  // TaskDispatched indicates that an agent has received the task, but
  // the agent has not yet told Evergreen that it's running the task
  Dispatched = "dispatched",

  // This is a temporary status which is the same as undispatched, but
  // with the additional info that it's waiting for a dependency
  Pending = "pending",

  // The statuses below indicate that a task has finished.
  Succeeded = "success",

  // These statuses indicate that the task failed, and it is likely a problem
  // with the code being tested
  Failed = "failed",
  TestTimedOut = "test-timed-out",
  TaskTimedOut = "task-timed-out",

  // These statuses indicate that the task failed, and it is likely a problem
  // with the systems running the task
  SetupFailed = "setup-failed",
  SystemFailed = "system-failed",
  SystemTimedOut = "system-timed-out",
  SystemUnresponsive = "system-unresponsive",

  // This status means that the task will not run because a dependency was
  // not satisfied
  Blocked = "blocked",
  Aborted = "aborted",

  KnownIssue = "known-issue",
}

// Task status sorted in order of "relevance", with the most likely actionable at the top.
export const SortedTaskStatus = [
  TaskStatus.Failed,
