    const user = userEvent.setup();
    const onChange = vi.fn();
    renderWithRouterMatch(
      <Pagination
        currentPage={0}
        onChange={onChange}
        pageSize={5}
        totalResults={10}
      />,
    );
    await user.click(screen.getByDataCy("next-page-button"));
